508	+/// Reconstruct a WHOLE pane response from its captured envelope: parse every
509	+/// section, re-render the modeled ones (signature / rules / restrictions) through
510	+/// the web path, carry opaque ones (fact symbols) verbatim, and reassemble
511	+/// through the skin replica. The result should byte-equal the input envelope.
512	+fn rebuild_pane(raw: &str) -> String {
513	+    let (html, title) = decode_envelope(raw);
514	+    let (leading, blocks) = parse_blocks(&unpostprocess(&html));
515	+    let mut bodies: Vec<(&str, String)> = Vec::new();
516	+    for (h, body) in &blocks {
517	+        let pt = plain(body);
518	+        let rendered = match h.as_str() {
519	+            "Signature" => web::render_signature_body(&parse_signature(&pt)),
520	+            "Construction Rules" | "Deconstruction Rules" => {
521	+                let rules: Vec<_> =
522	+                    split_at_heads(&pt, "rule ").iter().map(|b| parse_bare_rule(b)).collect();
523	+                web::render_bare_rules_body(&rules)
524	+            }
525	+            "Multiset Rewriting Rules" => {
526	+                let rules: Vec<_> =
527	+                    split_at_heads(&pt, "rule ").iter().map(|b| parse_rule_block(b)).collect();
528	+                web::render_msr_body(&rules)
529	+            }
530	+            "Restrictions of the Set of Traces" => {
531	+                let rs: Vec<_> = split_at_heads(&pt, "restriction ")
532	+                    .iter()
533	+                    .map(|b| parse_restriction_block(b))
534	+                    .collect();
535	+                web::render_restrictions_body(&rs)
536	+            }
537	+            // Opaque solver input (fact symbols, macros) ŌĆö carried verbatim.
538	+            _ => body.join("\n"),
539	+        };
540	+        bodies.push((h.as_str(), rendered));
541	+    }
542	+    let bref: Vec<(&str, Option<&str>)> =
543	+        bodies.iter().map(|(h, b)| (*h, Some(b.as_str()))).collect();
544	+    reassemble(&title, leading, &bref)
545	+}
