93	/// The column width a character occupies AFTER the entity escaping applied by
94	/// [`escape_and_expand`]: the length of its escaped form. Any character that is
95	/// not escaped keeps width 1 (non-ASCII glyphs `ŌłĆ Ōłā ŌćÆ ŌĆ”` are one scalar each and
96	/// pass raw). This is THE production layout charge.
97	fn escaped_char_width(c: char) -> usize {
98	    match c {
99	        '<' | '>' => 4, // &lt; &gt;
100	        '&' => 5,       // &amp;
101	        '"' => 6,       // &quot;
102	        '\'' => 5,      // &#39;
103	        _ => 1,
104	    }
105	}
106	
107	thread_local! {
108	    /// The per-character layout charge, [`escaped_char_width`] in all normal
109	    /// operation. Indirected through a cell so the acceptance suite alone can
110	    /// DOCTOR it (e.g. to glyph width) and prove the byte gate genuinely depends
111	    /// on the escaped charging ŌĆö see `escaped_charging_is_load_bearing`.
112	    static CHARGE: Cell<fn(char) -> usize> = Cell::new(escaped_char_width);
113	}
114	
115	/// The active layout charge for one character (the escaped width in production).
116	fn char_charge(c: char) -> usize {
117	    CHARGE.with(|k| k.get())(c)
118	}
119	
120	/// Layout charge for a whole string (sum of per-character charges).
121	fn escaped_width(s: &str) -> usize {
122	    s.chars().map(char_charge).sum()
123	}
124	
125	/// Web-aware `text`: in web mode the token is sized to its ESCAPED width while
126	/// its raw glyphs stay as the content (escaped later by [`escape_and_expand`]),
127	/// so the layout engine measures the escaped form. In batch mode it is exactly
128	/// `doc::text` ŌĆö the R1ŌĆōR5 output is byte-for-byte unchanged.
129	pub(crate) fn w_text(s: &str) -> Doc {
130	    if hl_on() {
131	        sized_text(escaped_width(s), s)
132	    } else {
133	        text(s)
134	    }
135	}
136	
137	/// Web-aware `char`: the escaped-width counterpart of `doc::char`.
138	pub(crate) fn w_char(c: char) -> Doc {
139	    if hl_on() {
140	        let mut buf = [0u8; 4];
141	        sized_text(char_charge(c), c.encode_utf8(&mut buf))
142	    } else {
143	        char(c)
144	    }
145	}
